  render: () => {
    const animate = useAnimation([{
      transform: "rotate(0deg)"
    }, {
      transform: "rotate(720deg)"
    }], {
      duration: 1000,
      easing: "ease-in-out"
    });
    return <Button ref={animate} variant="contained" onClick={() => {
      animate.play();
    }}>
        Click Me!
      </Button>;
  }
